mapper.select:
-- select id, user_id, family_rel, as_default, school_id, name, deleted, stage, gender, birthday, head_img, -- join_way, remark, graduation_date, graduation_reason, add_time, counselor, -- creator, editor, edit_time, idcard, redpoint_grade, redpoint_evaluate, -- grade, join_date, wx_access_id, credit, org_id, grade_id -- from student select s.id as id, s.name as name, u.mobile as phone, if(s.gender = 0, '男', '女') as sex, u.name as parentName, if(s.family_rel = 0, '直系亲属', '非直系亲属'), org.name as school, cg.name as grade, staff.name as counselor, s.birthday as birthday from student as s left join user as u on s.user_id = u.id left join org on s.school_id = org.id left join class_grade as cg on cg.id = s.grade_id left join staff on staff.id = s.counselor where s.stage = 0 and s.deleted = 0
and s.id in
#{id}

SELECT t1.id, t1.name, MAX(t8.name) as parentName, MAX(t1.family_rel) as familyRel, MAX(t8.mobile) as mobile, MAX(t3.name) as counselorName, MAX(t10.name) as gradeName, MAX(t4.name) as schoolName, CASE WHEN #{query.gradeId} IS NOT NULL THEN (select sum(count_lesson_total - count_lesson_complete - count_lesson_refund) from student_course where student_id = t1.id and grade_id = #{query.gradeId} and expire_date >= CURDATE()) ELSE IFNULL(sum(t5.count_lesson_total - t5.count_lesson_complete - t5.count_lesson_refund), 0) END as countLessonRemaining, MAX(t1.credit) as credit, MAX(t1.gender) as gender, MAX(TIMESTAMPDIFF(YEAR, t1.birthday, CURDATE())) AS age, MAX(t1.remark) as remark, MAX(t9.name) as joinWayName, MAX(t2.contact_time) as contactTime, MAX(t2.contact_next_time) as contactNextTime, MAX(t1.stage) as stage, MAX(t1.graduation_date) as graduationDate FROM student t1 LEFT JOIN user t8 on t8.id = t1.user_id LEFT JOIN staff t3 on t3.id = t1.counselor LEFT JOIN contact_record t2 on t2.student_id = t1.id AND t2.contact_time = (select max(contact_time) FROM contact_record where student_id = t1.id ) LEFT JOIN org t4 on t4.id = t1.school_id LEFT JOIN student_course t5 on t5.student_id = t1.id AND t5.expire_date >= CURDATE() AND t5.verify_state = 2 LEFT JOIN dict_item t9 on t9.id = t1.join_way LEFT JOIN class_grade t10 on t10.id = t1.grade_id
t1.deleted = 0
AND t1.stage = #{query.stage.code}
AND ( t1.name like concat('%', #{query.keyword}, '%') or t8.mobile like concat('%', #{query.keyword}, '%') )
AND t1.grade_id = #{query.gradeId}
GROUP BY t1.id ORDER BY t1.add_time DESC
